/**
 * /model command handler — switch between LLM providers.
 */
import { Context } from "grammy";
import { config } from "../config.js";
import type { ProviderType } from "../provider/types.js";
import { deps } from "./deps.js";

/** Alias map: user-friendly names → ProviderType */
const ALIASES: Record<string, ProviderType> = {
  kiro: "acp",
  acp: "acp",
  claude: "anthropic",
  "claude-api": "anthropic",
  anthropic: "anthropic",
  gpt4o: "openai",
  openai: "openai",
  gpt: "openai",
  gemini: "gemini",
  "gemini-flash": "gemini",
  google: "gemini",
  deepseek: "deepseek",
  groq: "groq",
  llama: "groq",
  local: "local",
  ollama: "local",
};

/** Display info for each provider type. */
const PROVIDER_INFO: Record<ProviderType, { label: string; model: () => string }> = {
  acp: { label: "Kiro CLI (ACP)", model: () => "claude-sonnet-4 via Bedrock" },
  anthropic: { label: "Anthropic API", model: () => config.models.anthropic },
  openai: { label: "OpenAI API", model: () => config.models.openai },
  gemini: { label: "Google Gemini", model: () => config.models.gemini },
  deepseek: { label: "DeepSeek API", model: () => config.models.deepseek },
  groq: { label: "Groq", model: () => config.models.groq },
  local: { label: "Local LLM", model: () => config.models.local },
};

export async function handleModel(ctx: Context): Promise<void> {
  const { isAllowed, sessions } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat?.id;
  const userId = ctx.from?.id;
  if (!chatId) return;

  const arg = (typeof ctx.match === "string" ? ctx.match : "").trim().toLowerCase();

  // No argument: show current model + available list
  if (!arg) {
    const session = sessions.peek(chatId);
    const current = session?.activeProvider ?? config.defaultProvider;
    const info = PROVIDER_INFO[current];
    const lines = [
      `🤖 當前模型：**${info.label}** (${info.model()})`,
      "",
      "可用模型：",
      ...Object.entries(PROVIDER_INFO).map(([type, p]) => {
        const marker = type === current ? " ← 當前" : "";
        const available = isAvailable(type as ProviderType);
        return `• \`${type}\` — ${p.label}${available ? "" : " ⚠️ 未設定 API key"}${marker}`;
      }),
      "",
      "用法：`/model <名稱>` 切換",
    ];
    await ctx.reply(lines.join("\n"), { parse_mode: "Markdown" });
    return;
  }

  // Resolve alias
  const type = ALIASES[arg];
  if (!type) {
    await ctx.reply(`❌ 未知模型 "${arg}"。用 /model 查看可用列表。`);
    return;
  }

  // Check availability
  if (!isAvailable(type)) {
    const envName = type === "local" ? "OLLAMA_URL" : `${type.toUpperCase()}_API_KEY`;
    await ctx.reply(`❌ ${PROVIDER_INFO[type].label} 未設定（需要 ${envName}）`);
    return;
  }

  // Check if already on this provider
  const session = sessions.peek(chatId);
  if (session?.activeProvider === type) {
    await ctx.reply(`已經在使用 ${PROVIDER_INFO[type].label} 了。`);
    return;
  }

  // Switch
  await ctx.reply(`🔄 切換到 ${PROVIDER_INFO[type].label} (${PROVIDER_INFO[type].model()})...\n⚠️ 對話歷史會重置。`);
  try {
    await (sessions as any).switchProvider(chatId, type, userId);
    await ctx.reply(`✅ 已切換到 **${PROVIDER_INFO[type].label}**`, { parse_mode: "Markdown" });
  } catch (err) {
    await ctx.reply(`❌ 切換失敗：${(err as Error).message}`);
  }
}

function isAvailable(type: ProviderType): boolean {
  if (type === "acp") return true; // always available
  if (type === "local") return true; // Ollama may or may not be running, but config is always there
  const key = type as keyof typeof config.apiKeys;
  return !!config.apiKeys[key];
}

