/**
 * Doctor Pattern — startup health check.
 * Runs after bot.start() confirms Telegram connectivity,
 * checks subsystems and notifies the user of results.
 */
import { existsSync } from "node:fs";
import { readFile, access } from "node:fs/promises";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import path from "node:path";
import { config } from "./config.js";
import { isEmbedRouterReady } from "./embed-router.js";
import { testRedisConnection } from "./relay.js";
import { detectLlamaCpp, getModel } from "./local-llm.js";

const execFileAsync = promisify(execFile);

export interface CheckResult {
  name: string;
  ok: boolean;
  detail?: string;
}

export async function runHealthCheck(): Promise<CheckResult[]> {
  const results: CheckResult[] = [];

  // 1. Memory directory exists + facts file readable
  results.push(await checkMemory());

  // 2. Embedding router loaded
  results.push(checkEmbedRouter());

  // 3. ACP agent command exists on PATH
  results.push(await checkAcpCommand());

  // 4. Relay (Redis) connectivity (if configured)
  if (config.relay) {
    results.push(await checkRelay());
  }

  // 5. Schedule file parseable
  results.push(await checkSchedules());

  // 6. llama.cpp local LLM server
  results.push(await checkLlamaCpp());

  return results;
}

async function checkMemory(): Promise<CheckResult> {
  const dir = config.memoryDir;
  if (!existsSync(dir)) {
    return { name: "Memory", ok: false, detail: `目錄不存在: ${dir}` };
  }
  const uid = config.allowedUserIds[0] ?? 0;
  const factsFile = path.join(dir, `facts-${uid}.md`);
  try {
    await access(factsFile);
    return { name: "Memory", ok: true };
  } catch {
    return { name: "Memory", ok: false, detail: `facts 檔不可讀: ${factsFile}` };
  }
}

function checkEmbedRouter(): CheckResult {
  return {
    name: "Embedding",
    ok: isEmbedRouterReady(),
    detail: isEmbedRouterReady() ? undefined : "router 未就緒",
  };
}

async function checkAcpCommand(): Promise<CheckResult> {
  const cmd = config.agent.command;
  try {
    await execFileAsync(cmd, ["--version"], { timeout: 5000, shell: true });
    return { name: "ACP Agent", ok: true };
  } catch (err: any) {
    // --version may not exist but if the binary is found it exits with code != ENOENT
    if (err?.code === "ENOENT") {
      return { name: "ACP Agent", ok: false, detail: `找不到指令: ${cmd}` };
    }
    // Binary exists but --version failed — still means it's reachable
    return { name: "ACP Agent", ok: true };
  }
}

async function checkRelay(): Promise<CheckResult> {
  try {
    const ok = await testRedisConnection(config.relay!);
    return { name: "Relay", ok, detail: ok ? undefined : "Redis 連線失敗" };
  } catch (err: any) {
    return { name: "Relay", ok: false, detail: err?.message ?? "unknown" };
  }
}

async function checkSchedules(): Promise<CheckResult> {
  const file = path.join(config.memoryDir, "schedules.json");
  try {
    const raw = await readFile(file, "utf8");
    JSON.parse(raw);
    return { name: "Schedules", ok: true };
  } catch (err: any) {
    if (err?.code === "ENOENT") {
      return { name: "Schedules", ok: true, detail: "無排程檔（正常）" };
    }
    return { name: "Schedules", ok: false, detail: `解析失敗: ${err.message}` };
  }
}

async function checkLlamaCpp(): Promise<CheckResult> {
  if (await detectLlamaCpp()) {
    return { name: "llama.cpp", ok: true, detail: getModel() ?? undefined };
  }
  return { name: "llama.cpp", ok: false, detail: "server 未啟動（需手動啟動 start-server.bat）" };
}

export function formatReport(results: CheckResult[]): string {
  const allOk = results.every((r) => r.ok);
  const icon = allOk ? "✅" : "⚠️";
  const lines = results.map((r) => {
    const status = r.ok ? "✓" : "✗";
    const extra = r.detail ? ` — ${r.detail}` : "";
    return `${status} ${r.name}${extra}`;
  });
  return `${icon} Health Check\n${lines.join("\n")}`;
}

