import { EventEmitter } from "node:events";

// ─── Event types ───────────────────────────────────────────────────────────

export interface SessionUpdate {
  sessionId: string;
  update: {
    sessionUpdate: string;
    [k: string]: unknown;
  };
}

export interface ProviderEvents {
  update: [u: SessionUpdate];
  stderr: [chunk: string];
  exit: [code: number | null];
  /** Agent→Client request (ACP only; Direct providers never emit this). */
  request: [req: { id: number | string; method: string; params?: unknown }];
}

// ─── Provider interface ────────────────────────────────────────────────────

/**
 * Abstraction over the agent backend. Both ACP (subprocess) and Direct
 * (LLM API + tool loop) implement this interface so SessionManager and
 * run-prompt don't need to know which one is active.
 */
export interface Provider extends EventEmitter {
  /** One-time initialization (connect MCP servers, create ACP session, etc.). Returns session ID. */
  initialize(): Promise<string>;
  /** Send a user prompt and wait for the turn to complete. Streaming via 'update' events. */
  prompt(text: string): Promise<{ stopReason: string }>;
  /** Cancel the in-flight prompt. */
  cancel(): void;
  /** Graceful shutdown. */
  close(): Promise<void>;
  /** Whether the provider process/connection is dead. */
  readonly isClosed: boolean;
  /** Human-readable provider name for logging (e.g. "acp", "claude-api", "local"). */
  readonly name: string;
}

// ─── Provider config ───────────────────────────────────────────────────────

export type ProviderType = "acp" | "anthropic" | "openai" | "gemini" | "deepseek" | "groq" | "local";

export interface ProviderConfig {
  type: ProviderType;
  /** Display name for /model command. */
  label: string;
  /** Model identifier sent to the API. */
  model?: string;
  /** API base URL (openai-compat). */
  baseUrl?: string;
  /** API key env var name (resolved at runtime). */
  apiKeyEnv?: string;
}

