/**
 * Anthropic Messages API streaming adapter.
 * Claude uses a different format from OpenAI: content blocks, separate system field,
 * tool_use/tool_result content blocks instead of function calling.
 */
import type { ChatMessage, LlmAdapter, ToolCall, ToolDef } from "../tool-loop.js";

export interface AnthropicConfig {
  apiKey: string;
  model: string;
  maxTokens?: number;
  baseUrl?: string;
}

export class AnthropicAdapter implements LlmAdapter {
  private baseUrl: string;

  constructor(private cfg: AnthropicConfig) {
    this.baseUrl = cfg.baseUrl ?? "https://api.anthropic.com";
  }

  async chat(
    messages: ChatMessage[],
    opts: { tools?: ToolDef[]; onText?: (chunk: string) => void; onThinking?: (chunk: string) => void },
  ): Promise<{ message: ChatMessage; stopReason: string }> {
    // Separate system from conversation messages
    const system = messages.filter((m) => m.role === "system").map((m) => String(m.content)).join("\n\n");
    const conversation = messages.filter((m) => m.role !== "system").map(toAnthropicMessage);

    const body: Record<string, unknown> = {
      model: this.cfg.model,
      max_tokens: this.cfg.maxTokens ?? 16384,
      stream: true,
      messages: conversation,
    };
    if (system) {
      body.system = [{ type: "text", text: system, cache_control: { type: "ephemeral" } }];
    }
    if (opts.tools && opts.tools.length > 0) {
      body.tools = opts.tools.map(toAnthropicTool);
    }

    const res = await fetch(`${this.baseUrl}/v1/messages`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": this.cfg.apiKey,
        "anthropic-version": "2023-06-01",
      },
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text().catch(() => "");
      throw new Error(`Anthropic API ${res.status}: ${text.slice(0, 500)}`);
    }

    return this.parseSSE(res, opts.onText, opts.onThinking);
  }

  private async parseSSE(
    res: Response,
    onText?: (chunk: string) => void,
    onThinking?: (chunk: string) => void,
  ): Promise<{ message: ChatMessage; stopReason: string }> {
    const reader = res.body!.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let fullText = "";
    let stopReason = "end_turn";
    const toolUseBlocks: { id: string; name: string; args: string }[] = [];
    let currentToolIdx = -1;

    for (;;) {
      const { done, value } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });

      const lines = buffer.split("\n");
      buffer = lines.pop()!;

      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const data = line.slice(6).trim();
        if (!data) continue;

        let event: any;
        try { event = JSON.parse(data); } catch { continue; }

        switch (event.type) {
          case "content_block_start": {
            const block = event.content_block;
            if (block?.type === "tool_use") {
              currentToolIdx = toolUseBlocks.length;
              toolUseBlocks.push({ id: block.id, name: block.name, args: "" });
            }
            break;
          }
          case "content_block_delta": {
            const delta = event.delta;
            if (delta?.type === "text_delta") {
              fullText += delta.text;
              onText?.(delta.text);
            } else if (delta?.type === "thinking_delta") {
              onThinking?.(delta.thinking);
            } else if (delta?.type === "input_json_delta" && currentToolIdx >= 0) {
              toolUseBlocks[currentToolIdx].args += delta.partial_json;
            }
            break;
          }
          case "content_block_stop":
            break;
          case "message_delta":
            if (event.delta?.stop_reason) {
              stopReason = event.delta.stop_reason;
            }
            break;
        }
      }
    }

    // Build assistant message in OpenAI tool_calls format (tool-loop expects this)
    const message: ChatMessage = { role: "assistant", content: fullText };
    if (toolUseBlocks.length > 0) {
      stopReason = "tool_use";
      message.tool_calls = toolUseBlocks.map((tb) => ({
        id: tb.id,
        type: "function" as const,
        function: { name: tb.name, arguments: tb.args },
      }));
    }

    return { message, stopReason };
  }
}

// ─── Format conversion ─────────────────────────────────────────────────────

function toAnthropicMessage(msg: ChatMessage): Record<string, unknown> {
  if (msg.role === "assistant") {
    const content: any[] = [];
    if (msg.content) content.push({ type: "text", text: String(msg.content) });
    if (msg.tool_calls) {
      for (const tc of msg.tool_calls) {
        let input: unknown;
        try { input = JSON.parse(tc.function.arguments); } catch { input = {}; }
        content.push({ type: "tool_use", id: tc.id, name: tc.function.name, input });
      }
    }
    return { role: "assistant", content };
  }

  if (msg.role === "tool") {
    return {
      role: "user",
      content: [{ type: "tool_result", tool_use_id: msg.tool_call_id, content: String(msg.content) }],
    };
  }

  // user
  return { role: "user", content: String(msg.content) };
}

function toAnthropicTool(def: ToolDef): Record<string, unknown> {
  return {
    name: def.function.name,
    description: def.function.description ?? "",
    input_schema: def.function.parameters,
  };
}

