1	/**
2	 * OpenAI-compatible streaming chat completion adapter.
3	 * Works with: OpenAI, DeepSeek, Groq, Mistral, Together, Ollama.
4	 * Differences are just baseURL + apiKey + model name.
5	 */
6	import type { ChatMessage, LlmAdapter, ToolCall, ToolDef } from "../tool-loop.js";
7	
8	export interface OpenAICompatConfig {
9	  baseUrl: string;
10	  apiKey: string;
11	  model: string;
12	  /** Disable thinking/reasoning mode (required for qwen3 on Ollama). */
13	  disableThinking?: boolean;
14	  /** Ollama num_ctx override (default 2048 is too small for bridge preamble). */
15	  numCtx?: number;
16	}
17	
18	export class OpenAICompatAdapter implements LlmAdapter {
19	  constructor(private cfg: OpenAICompatConfig) {}
20	
21	  async chat(
22	    messages: ChatMessage[],
23	    opts: { tools?: ToolDef[]; onText?: (chunk: string) => void; onThinking?: (chunk: string) => void },
24	  ): Promise<{ message: ChatMessage; stopReason: string }> {
25	    const body: Record<string, unknown> = {
26	      model: this.cfg.model,
27	      messages: messages.map(toOpenAIMessage),
28	      stream: true,
29	    };
30	    if (this.cfg.numCtx) {
31	      body.options = { num_ctx: this.cfg.numCtx };
32	    }
33	    if (opts.tools && opts.tools.length > 0) {
34	      body.tools = opts.tools;
35	    }
36	
37	    const res = await fetch(`${this.cfg.baseUrl}/chat/completions`, {
38	      method: "POST",
39	      headers: {
40	        "Content-Type": "application/json",
41	        ...(this.cfg.apiKey ? { Authorization: `Bearer ${this.cfg.apiKey}` } : {}),
42	      },
43	      body: JSON.stringify(body),
44	    });
45	
46	    if (!res.ok) {
47	      const text = await res.text().catch(() => "");
48	      throw new Error(`OpenAI API ${res.status}: ${text.slice(0, 500)}`);
49	    }
50	
51	    return this.parseSSE(res, opts.onText, opts.onThinking);
52	  }
53	
54	  private async parseSSE(
55	    res: Response,
56	    onText?: (chunk: string) => void,
57	    onThinking?: (chunk: string) => void,
58	  ): Promise<{ message: ChatMessage; stopReason: string }> {
59	    const reader = res.body!.getReader();
60	    const decoder = new TextDecoder();
61	    let buffer = "";
62	    let fullText = "";
63	    let fullReasoning = "";
64	    let toolCalls: Map<number, { id: string; name: string; args: string }> = new Map();
65	    let stopReason = "end_turn";
66	
67	    for (;;) {
68	      const { done, value } = await reader.read();
69	      if (done) break;
70	      buffer += decoder.decode(value, { stream: true });
71	
72	      const lines = buffer.split("\n");
73	      buffer = lines.pop()!; // keep incomplete line
74	
75	      for (const line of lines) {
76	        if (!line.startsWith("data: ")) continue;
77	        const data = line.slice(6).trim();
78	        if (data === "[DONE]") continue;
79	
80	        let parsed: any;
81	        try { parsed = JSON.parse(data); } catch { continue; }
82	
83	        const delta = parsed.choices?.[0]?.delta;
84	        const finishReason = parsed.choices?.[0]?.finish_reason;
85	
86	        if (finishReason) {
87	          stopReason = finishReason === "tool_calls" ? "tool_use" : finishReason;
88	        }
89	
90	        if (!delta) continue;
91	
92	        // Text content
93	        if (delta.content) {
94	          fullText += delta.content;
95	          onText?.(delta.content);
96	        }
97	
98	        // Reasoning/thinking content (qwen3, DeepSeek-R1, etc.)
99	        if (delta.reasoning) {
100	          fullReasoning += delta.reasoning;
101	          onThinking?.(delta.reasoning);
102	        }
103	
104	        // Tool calls (streamed incrementally)
105	        if (delta.tool_calls) {
106	          for (const tc of delta.tool_calls) {
107	            const idx = tc.index ?? 0;
108	            if (!toolCalls.has(idx)) {
109	              toolCalls.set(idx, { id: tc.id ?? "", name: "", args: "" });
110	            }
111	            const entry = toolCalls.get(idx)!;
112	            if (tc.id) entry.id = tc.id;
113	            if (tc.function?.name) entry.name += tc.function.name;
114	            if (tc.function?.arguments) entry.args += tc.function.arguments;
115	          }
116	        }
117	      }
118	    }
