/**
 * OpenAI-compatible streaming chat completion adapter.
 * Works with: OpenAI, DeepSeek, Groq, Mistral, Together, Ollama.
 * Differences are just baseURL + apiKey + model name.
 */
import type { ChatMessage, LlmAdapter, ToolCall, ToolDef } from "../tool-loop.js";

export interface OpenAICompatConfig {
  baseUrl: string;
  apiKey: string;
  model: string;
  /** Disable thinking/reasoning mode (required for qwen3 on Ollama). */
  disableThinking?: boolean;
  /** Ollama num_ctx override (default 2048 is too small for bridge preamble). */
  numCtx?: number;
}

export class OpenAICompatAdapter implements LlmAdapter {
  constructor(private cfg: OpenAICompatConfig) {}

  async chat(
    messages: ChatMessage[],
    opts: { tools?: ToolDef[]; onText?: (chunk: string) => void; onThinking?: (chunk: string) => void },
  ): Promise<{ message: ChatMessage; stopReason: string }> {
    const body: Record<string, unknown> = {
      model: this.cfg.model,
      messages: messages.map(toOpenAIMessage),
      stream: true,
    };
    if (this.cfg.numCtx) {
      body.options = { num_ctx: this.cfg.numCtx };
    }
    if (opts.tools && opts.tools.length > 0) {
      body.tools = opts.tools;
    }

    const res = await fetch(`${this.cfg.baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        ...(this.cfg.apiKey ? { Authorization: `Bearer ${this.cfg.apiKey}` } : {}),
      },
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text().catch(() => "");
      throw new Error(`OpenAI API ${res.status}: ${text.slice(0, 500)}`);
    }

    return this.parseSSE(res, opts.onText, opts.onThinking);
  }

  private async parseSSE(
    res: Response,
    onText?: (chunk: string) => void,
    onThinking?: (chunk: string) => void,
  ): Promise<{ message: ChatMessage; stopReason: string }> {
    const reader = res.body!.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let fullText = "";
    let fullReasoning = "";
    let toolCalls: Map<number, { id: string; name: string; args: string }> = new Map();
    let stopReason = "end_turn";

    for (;;) {
      const { done, value } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });

      const lines = buffer.split("\n");
      buffer = lines.pop()!; // keep incomplete line

      for (const line of lines) {
        if (!line.startsWith("data: ")) continue;
        const data = line.slice(6).trim();
        if (data === "[DONE]") continue;

        let parsed: any;
        try { parsed = JSON.parse(data); } catch { continue; }

        const delta = parsed.choices?.[0]?.delta;
        const finishReason = parsed.choices?.[0]?.finish_reason;

        if (finishReason) {
          stopReason = finishReason === "tool_calls" ? "tool_use" : finishReason;
        }

        if (!delta) continue;

        // Text content
        if (delta.content) {
          fullText += delta.content;
          onText?.(delta.content);
        }

        // Reasoning/thinking content (qwen3, DeepSeek-R1, etc.)
        if (delta.reasoning) {
          fullReasoning += delta.reasoning;
          onThinking?.(delta.reasoning);
        }

        // Tool calls (streamed incrementally)
        if (delta.tool_calls) {
          for (const tc of delta.tool_calls) {
            const idx = tc.index ?? 0;
            if (!toolCalls.has(idx)) {
              toolCalls.set(idx, { id: tc.id ?? "", name: "", args: "" });
            }
            const entry = toolCalls.get(idx)!;
            if (tc.id) entry.id = tc.id;
            if (tc.function?.name) entry.name += tc.function.name;
            if (tc.function?.arguments) entry.args += tc.function.arguments;
          }
        }
      }
    }

    // If model produced only reasoning (no content), use reasoning as the response
    if (!fullText && fullReasoning && toolCalls.size === 0) {
      fullText = fullReasoning;
      onText?.(fullReasoning);
    }

    // Build the assistant message
    const message: ChatMessage = { role: "assistant", content: fullText };
    if (toolCalls.size > 0) {
      message.tool_calls = [...toolCalls.values()].map((tc) => ({
        id: tc.id,
        type: "function" as const,
        function: { name: tc.name, arguments: tc.args },
      }));
    }

    return { message, stopReason };
  }
}

// ─── Message format conversion ─────────────────────────────────────────────

function toOpenAIMessage(msg: ChatMessage): Record<string, unknown> {
  const out: Record<string, unknown> = { role: msg.role };

  if (msg.role === "tool") {
    out.tool_call_id = msg.tool_call_id;
    out.content = typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content);
    return out;
  }

  if (msg.tool_calls) {
    out.tool_calls = msg.tool_calls;
    out.content = typeof msg.content === "string" ? (msg.content || null) : null;
    return out;
  }

  out.content = typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content);
  return out;
}

