/**
 * Error classification — routes errors to the appropriate handling strategy.
 * LLM-first when LOCAL_LLM_ERROR_CLASSIFY=true + Ollama available,
 * otherwise falls back to regex pattern matching.
 */
import { detectLlamaCpp, localComplete } from "./local-llm.js";

export interface ErrorClassification {
  category: string;
  confidence: number;
  suggestedSkill: string | null;
}

const CATEGORIES: Array<{
  category: string;
  patterns: RegExp[];
  skill: string | null;
}> = [
  { category: "syntax-error", patterns: [/SyntaxError/i, /unexpected token/i, /parse error/i], skill: null },
  { category: "type-error", patterns: [/TypeError/i, /is not a function/i, /cannot read propert/i, /undefined is not/i], skill: "ms-causal-chain-analysis" },
  { category: "module-not-found", patterns: [/Cannot find module/i, /MODULE_NOT_FOUND/i, /no such file/i, /ENOENT/i], skill: "ms-diagnose" },
  { category: "permission-denied", patterns: [/EPERM/i, /EACCES/i, /permission denied/i, /\b403\b/], skill: "ms-windows-node-atomic-write" },
  { category: "rate-limit", patterns: [/429/i, /retry_after/i, /flood control/i, /Too Many Requests/i], skill: "ms-telegram-bot-rate-limit-survival" },
  { category: "network-timeout", patterns: [/ETIMEDOUT/i, /ECONNREFUSED/i, /socket hang up/i, /ECONNRESET/i], skill: "ms-telegram-bot-rate-limit-survival" },
  { category: "shell-false-positive", patterns: [/exit code:?\s*1/i], skill: "ms-windows-shell-exit-code-false-positive" },
  { category: "shell-interactive-hang", patterns: [/cmdlet .* at command pipeline/i, /Supply values for/i], skill: "ms-windows-shell-interactive-prompt" },
  { category: "silent-fail", patterns: [/Successfully replaced 0/i, /no occurrences/i], skill: "ms-kiro-strreplace-silent-fail" },
  { category: "llm-parse-error", patterns: [/JSON\.parse/i, /Unexpected token.*JSON/i, /SyntaxError.*JSON/i], skill: "ms-llm-json-extraction-parsing" },
  { category: "llm-cold-start", patterns: [/model.*loading/i, /ollama.*timeout/i, /empty response from/i], skill: "ms-ollama-local-llm-integration" },
  { category: "editor-ipc-error", patterns: [/Message does not exist/i, /scene worker/i], skill: "ms-cocos-362-editor-ipc" },
  { category: "path-mismatch", patterns: [/not in allowed/i, /startsWith.*failed/i, /SEND_ROOTS/i], skill: "ms-windows-path-prefix-check" },
  { category: "ast-refactor-break", patterns: [/pattern_rewrite/i, /infinite recursion/i, /Maximum call stack/i], skill: "ms-ast-grep-refactor-safety" },
];

function regexClassify(errorText: string): ErrorClassification {
  for (const { category, patterns, skill } of CATEGORIES) {
    if (patterns.some(p => p.test(errorText))) {
      return { category, confidence: 0.7, suggestedSkill: skill };
    }
  }
  return { category: "unknown", confidence: 0.3, suggestedSkill: "ms-diagnose" };
}

const LLM_FLAG = () => (process.env.LOCAL_LLM_ERROR_CLASSIFY ?? "").toLowerCase() === "true";

export async function classifyError(errorText: string): Promise<ErrorClassification> {
  if (!LLM_FLAG()) return regexClassify(errorText);

  const ok = await detectLlamaCpp();
  if (!ok) return regexClassify(errorText);

  const categoryList = CATEGORIES.map(c => c.category).join(", ");
  const prompt =
    `Classify this error into exactly one category.\n` +
    `Categories: ${categoryList}, unknown\n\n` +
    `Error: "${errorText.slice(0, 300)}"\n\n` +
    `Output ONLY the category name, nothing else.`;

  try {
    const raw = await localComplete(prompt, { maxTokens: 20, timeout: 8000, temperature: 0 });
    const label = raw.trim().toLowerCase().replace(/[^a-z-]/g, "");
    const match = CATEGORIES.find(c => c.category === label);
    if (match) {
      return { category: match.category, confidence: 0.85, suggestedSkill: match.skill };
    }
  } catch { /* fallback */ }

  return regexClassify(errorText);
}

