// AB-2 smoke test: atomicJson helper correctness.
//
// Verifies:
//   1. readJsonOrDefault ENOENT → fallback
//   2. readJsonOrDefault corrupt JSON → fallback (with log)
//   3. atomicWriteJson round-trip
//   4. atomicWriteJson does NOT leave .tmp-* residue on success
//   5. updateJson: 50 concurrent increments land all 50 (no lost updates)
//   6. updateJson: ENOENT uses `initial`, not throws
//
// Run: node scripts/check-atomic-json.mjs
// Uses compiled dist/atomicJson.js — run `tsc` first.

import { mkdir, readFile, readdir, rm, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import {
  atomicWriteJson,
  readJsonOrDefault,
  updateJson,
} from "../dist/atomicJson.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const tmpDir = path.join(__dirname, "..", "tmp", "check-atomic-json");

async function fresh() {
  await rm(tmpDir, { recursive: true, force: true });
  await mkdir(tmpDir, { recursive: true });
}

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`✅ ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`❌ ${name}: ${detail}`);
}

