/**
 * quota-error — 判斷 LLM provider 錯誤是否為「額度用盡」或「限流/過載」，
 * 並產生給使用者的 /model 切換提示。
 *
 * 攔截點：run-prompt.ts 的 prompt 失敗 catch（所有 provider 錯誤的統一出口）。
 * Direct adapter 的錯誤格式是 "Anthropic API 429: {...}" / "OpenAI API 429: {...}"；
 * ACP (Kiro) 的額度錯誤通常出現在 stderr tail，呼叫端把兩者併起來傳入即可。
 */

export type QuotaErrorKind = "quota-exhausted" | "rate-limited";

/** 額度用盡（非暫時性）— 建議直接切換模型。 */
const QUOTA_PATTERNS: RegExp[] = [
  /insufficient[_ ]quota/i,          // OpenAI
  /exceeded your current quota/i,    // OpenAI / Gemini
  /insufficient balance/i,           // DeepSeek (402)
  /credit balance is too low/i,      // Anthropic
  /\bAPI 402\b/,                     // adapter 格式："OpenAI API 402: ..."
  /usage limit/i,                    // Kiro / 訂閱制用量上限
  /monthly.{0,20}limit/i,            // 月額度類訊息
];

/** 限流 / 過載（暫時性）— 可稍後重試，或切換模型。 */
const RATE_PATTERNS: RegExp[] = [
  /\bAPI 429\b/,                     // adapter 格式："Anthropic API 429: ..."
  /rate[_ ]?limit/i,                 // rate_limit_error / rate limit exceeded
  /too many requests/i,
  /RESOURCE_EXHAUSTED/,              // Gemini
  /\bAPI 529\b/,                     // Anthropic overloaded
  /overloaded/i,                     // Anthropic overloaded_error
];

/** 分類錯誤文字。額度用盡優先於限流（429 + insufficient_quota 算額度用盡）。 */
export function classifyQuotaError(text: string): QuotaErrorKind | null {
  if (QUOTA_PATTERNS.some((p) => p.test(text))) return "quota-exhausted";
  if (RATE_PATTERNS.some((p) => p.test(text))) return "rate-limited";
  return null;
}

/** 命中額度/限流錯誤時回傳使用者提示，否則回傳 null。 */
export function quotaHint(text: string): string | null {
  const kind = classifyQuotaError(text);
  if (kind === "quota-exhausted") {
    return "💡 看起來是模型額度已用盡。可用 /model 查看並切換其他模型（切換會重置對話）。";
  }
  if (kind === "rate-limited") {
    return "💡 看起來是模型限流或過載。可稍後重試，或用 /model 切換其他模型（切換會重置對話）。";
  }
  return null;
}

