// Smoke test: quota-error 額度/限流錯誤分類 + /model 切換提示。
//
// Verifies:
//   1. Direct adapter 429 格式 → rate-limited 提示
//   2. OpenAI insufficient_quota → quota-exhausted 提示（優先於 429）
//   3. DeepSeek Insufficient Balance / 402 → quota-exhausted
//   4. Anthropic credit balance too low → quota-exhausted
//   5. Anthropic 529 overloaded → rate-limited
//   6. Gemini RESOURCE_EXHAUSTED → rate-limited
//   7. Kiro/訂閱 usage limit（stderr 風格）→ quota-exhausted
//   8. 一般錯誤（ENOENT / TypeError / 500）→ null，不誤附提示
//
// Run: node scripts/check-quota-hint.mjs
// Uses compiled dist/provider/quota-error.js — run `tsc` first.

import { classifyQuotaError, quotaHint } from "../dist/provider/quota-error.js";

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`✅ ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`❌ ${name}: ${detail}`);
}

function expectKind(name, text, expected) {
  const got = classifyQuotaError(text);
  if (got === expected) ok(name);
  else fail(name, `expected ${expected}, got ${got}`);
}

// 1. Direct adapter 429 格式
expectKind(
  "Anthropic API 429 → rate-limited",
  'Anthropic API 429: {"type":"error","error":{"type":"rate_limit_error","message":"..."}}',
  "rate-limited",
);
expectKind(
  "OpenAI API 429 (無 quota 字樣) → rate-limited",
  "OpenAI API 429: Too Many Requests",
  "rate-limited",
);

// 2. quota 優先於 429
expectKind(
  "429 + insufficient_quota → quota-exhausted（優先）",
  'OpenAI API 429: {"error":{"code":"insufficient_quota","message":"You exceeded your current quota"}}',
  "quota-exhausted",
);

// 3. DeepSeek 402
expectKind(
  "DeepSeek 402 Insufficient Balance → quota-exhausted",
  "OpenAI API 402: Insufficient Balance",
  "quota-exhausted",
);

// 4. Anthropic credit
expectKind(
  "Anthropic credit balance too low → quota-exhausted",
  "Anthropic API 400: Your credit balance is too low to access the Anthropic API",
  "quota-exhausted",
);

// 5. Anthropic 529
expectKind(
  "Anthropic API 529 overloaded → rate-limited",
  'Anthropic API 529: {"error":{"type":"overloaded_error"}}',
  "rate-limited",
);

// 6. Gemini
expectKind(
  "Gemini RESOURCE_EXHAUSTED → rate-limited",
  'OpenAI API 429: {"error":{"status":"RESOURCE_EXHAUSTED"}}',
  "rate-limited",
);

// 7. Kiro/訂閱 usage limit（stderr 風格，混在多行文字裡）
expectKind(
  "usage limit in stderr → quota-exhausted",
  "Error: Internal error\nstderr: You have reached your monthly usage limit.",
  "quota-exhausted",
);

// 8. 一般錯誤不誤判
for (const [name, text] of [
  ["ENOENT 不誤判", "Error: ENOENT: no such file or directory, open 'x.json'"],
  ["TypeError 不誤判", "TypeError: Cannot read properties of undefined (reading 'foo')"],
  ["HTTP 500 不誤判", "OpenAI API 500: Internal Server Error"],
  ["內文含 4290 數字不誤判", "Error: value 4290 out of range"],
]) {
  const got = classifyQuotaError(text);
  if (got === null) ok(name);
  else fail(name, `expected null, got ${got}`);
}

// hint 文案檢查：兩種類別都要提到 /model
{
  const q = quotaHint("OpenAI API 402: Insufficient Balance");
  if (q && q.includes("/model") && q.includes("額度")) ok("quota hint 含 /model + 額度");
  else fail("quota hint 含 /model + 額度", `got: ${q}`);

  const r = quotaHint("Anthropic API 429: rate_limit_error");
  if (r && r.includes("/model")) ok("rate-limit hint 含 /model");
  else fail("rate-limit hint 含 /model", `got: ${r}`);

  const n = quotaHint("Error: something else");
  if (n === null) ok("非額度錯誤 hint 為 null");
  else fail("非額度錯誤 hint 為 null", `got: ${n}`);
}

const failed = results.filter((r) => !r.pass);
console.log(`\n${results.length - failed.length}/${results.length} passed`);
process.exit(failed.length > 0 ? 1 : 0);

